import { useState } from "react";
import { useLocation } from "wouter";
import Layout from "@/components/layout/Layout";
import { trpc } from "@/lib/trpc";
import { useAuth } from "@/hooks/useAuth";
import { toast } from "sonner";

const PLANS = [
  { slug: "basic",   name: "Basic",   price: 97,  desc: "Para profissionais autônomos",  color: "#2563eb",        features: ["3 projetos ativos", "5 concorrentes/projeto", "3 campanhas IA/mês", "Integração Meta Ads", "Suporte por e-mail"] },
  { slug: "premium", name: "Premium", price: 197, desc: "Para agências e times",          color: "var(--green-d)", highlight: true, features: ["10 projetos ativos", "Concorrentes ilimitados", "Campanhas IA ilimitadas", "Meta + Google Ads", "Export PDF e XLSX", "Suporte prioritário"] },
  { slug: "vip",     name: "VIP",     price: 397, desc: "Para grandes operações",         color: "#7c3aed",        features: ["Projetos ilimitados", "Tudo do Premium", "API access", "Manager dedicado", "Onboarding personalizado"] },
];

// Payloads Pix Copia e Cola — chave: contato@mecproai.com
const PIX_DATA: Record<string, { payload: string; qr?: string; valor: number }> = {
  "basic_monthly": { payload: "00020126480014BR.GOV.BCB.PIX0126contato@mecproai.com520400005303986540597.005802BR5906MECPro6015Blneario Cambor62180514MECProBasicMes63046961", qr: "data:image/png;base64,", valor: 97.0 },
  "premium_monthly": { payload: "00020126480014BR.GOV.BCB.PIX0126contato@mecproai.com5204000053039865406197.005802BR5906MECPro6015Blneario Cambor62190515MECProPremiumMs63042F7E", qr: "data:image/png;base64,", valor: 197.0 },
  "vip_monthly": { payload: "00020126480014BR.GOV.BCB.PIX0126contato@mecproai.com5204000053039865406397.005802BR5906MECPro6015Blneario Cambor62190515MECProVIPMensal6304D9C8", qr: "data:image/png;base64,", valor: 397.0 },
  "basic_yearly": { payload: "00020126480014BR.GOV.BCB.PIX0126contato@mecproai.com5204000053039865406931.205802BR5906MECPro6015Blneario Cambor62180514MECProBasicAno6304B1DE", valor: 931.2 },
  "premium_yearly": { payload: "00020126480014BR.GOV.BCB.PIX0126contato@mecproai.com52040000530398654071891.205802BR5906MECPro6015Blneario Cambor62170513MECProPremAno6304AB78", valor: 1891.2 },
  "vip_yearly": { payload: "00020126480014BR.GOV.BCB.PIX0126contato@mecproai.com52040000530398654073811.205802BR5906MECPro6015Blneario Cambor62180514MECProVIPAnual6304452C", valor: 3811.2 },
};

const PLAN_EMOJI: Record<string, string> = { basic: "⚡", premium: "⭐", vip: "👑" };

interface PixModalProps {
  plan: typeof PLANS[0];
  billing: "monthly" | "yearly";
  onClose: () => void;
}

function PixModal({ plan, billing, onClose }: PixModalProps) {
  const [copied, setCopied] = useState(false);
  const key   = `${plan.slug}_${billing}`;
  const pix   = PIX_DATA[key];
  const price = billing === "yearly" ? Math.round(plan.price * 0.8) : plan.price;

  if (!pix) return null;

  function copy() {
    navigator.clipboard.writeText(pix.payload).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 4000);
    });
  }

  return (
    <div
      style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.6)", zIndex:1000, display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}
      onClick={onClose}>
      <div onClick={e => e.stopPropagation()} style={{ background:"white", borderRadius:20, padding:28, maxWidth:420, width:"100%", boxShadow:"0 24px 60px rgba(0,0,0,.25)" }}>

        {/* Header */}
        <div style={{ display:"flex", alignItems:"center", gap:12, marginBottom:20 }}>
          <div style={{ background:"#e0faf6", borderRadius:12, width:44, height:44, display:"flex", alignItems:"center", justifyContent:"center", fontSize:22, flexShrink:0 }}>
            🏦
          </div>
          <div>
            <p style={{ fontWeight:800, fontSize:16, color:"var(--black)", marginBottom:2 }}>Pagar com Pix</p>
            <p style={{ fontSize:12, color:"var(--muted)" }}>{PLAN_EMOJI[plan.slug]} Plano {plan.name} — {billing === "yearly" ? "Anual" : "Mensal"}</p>
          </div>
          <button onClick={onClose} style={{ marginLeft:"auto", background:"none", border:"none", fontSize:20, cursor:"pointer", color:"var(--muted)" }}>✕</button>
        </div>

        {/* Valor */}
        <div style={{ background:"linear-gradient(135deg,#f0fdf4,#dcfce7)", borderRadius:14, padding:"16px 20px", marginBottom:20, textAlign:"center" }}>
          <p style={{ fontSize:12, color:"#16a34a", fontWeight:600, marginBottom:4 }}>💰 Valor do Pix</p>
          <p style={{ fontSize:36, fontWeight:800, color:"#15803d", fontFamily:"var(--font-display)" }}>
            R$ {pix.valor.toFixed(2).replace(".", ",")}
          </p>
          {billing === "yearly" && (
            <p style={{ fontSize:12, color:"#16a34a", marginTop:4 }}>✅ 12 meses com 20% de desconto (R$ {price}/mês)</p>
          )}
        </div>

        {/* Instruções */}
        <div style={{ marginBottom:16 }}>
          <p style={{ fontSize:13, fontWeight:700, color:"var(--black)", marginBottom:10 }}>Como pagar:</p>
          {[
            "Abra o app do seu banco",
            "Vá em Pix → Pix Copia e Cola",
            "Cole o código abaixo e confirme",
            "Envie o comprovante pelo WhatsApp",
          ].map((s, i) => (
            <div key={i} style={{ display:"flex", gap:10, alignItems:"flex-start", marginBottom:8 }}>
              <span style={{ background:"#1a9e90", color:"white", borderRadius:"50%", width:20, height:20, display:"flex", alignItems:"center", justifyContent:"center", fontSize:11, fontWeight:700, flexShrink:0, marginTop:1 }}>{i+1}</span>
              <span style={{ fontSize:13, color:"var(--body)" }}>{s}</span>
            </div>
          ))}
        </div>

        {/* Chave pix */}
        <div style={{ background:"#f8fafc", border:"1px solid var(--border)", borderRadius:10, padding:"10px 14px", marginBottom:12 }}>
          <p style={{ fontSize:11, color:"var(--muted)", marginBottom:2 }}>Chave Pix (e-mail)</p>
          <p style={{ fontSize:13, fontWeight:700, color:"var(--black)" }}>contato@mecproai.com</p>
        </div>

        {/* Código copia e cola */}
        <div style={{ background:"#f1f5f9", border:"1px solid #e2e8f0", borderRadius:10, padding:"10px 14px", marginBottom:14, wordBreak:"break-all" }}>
          <p style={{ fontSize:11, color:"var(--muted)", marginBottom:4 }}>Código Pix Copia e Cola</p>
          <p style={{ fontSize:10, color:"var(--black)", fontFamily:"monospace", lineHeight:1.5 }}>{pix.payload}</p>
        </div>

        {/* Botão copiar */}
        <button onClick={copy} style={{
          width:"100%", padding:"13px 20px", borderRadius:12,
          background: copied ? "#16a34a" : "#1a9e90",
          color:"white", fontWeight:700, fontSize:14,
          border:"none", cursor:"pointer", marginBottom:12, transition:"background .2s"
        }}>
          {copied ? "✅ Código copiado! Cole no seu app" : "📋 Copiar código Pix"}
        </button>

        {/* Aviso comprovante */}
        <div style={{ background:"#fef9c3", border:"1px solid #fde68a", borderRadius:10, padding:"12px 14px", marginBottom:16 }}>
          <p style={{ fontSize:12, fontWeight:700, color:"#92400e", marginBottom:4 }}>⚠️ Após pagar</p>
          <p style={{ fontSize:12, color:"#b45309" }}>
            Envie o comprovante para ativarmos seu plano em até <strong>2 horas</strong>:
          </p>
          <p style={{ fontSize:12, color:"#b45309", marginTop:4 }}>
            <strong>Michel Leal</strong> — Gerente de Relacionamento<br/>
            📱 WhatsApp: <strong>(47) 99465-824</strong><br/>
            📧 E-mail: <strong>contato@mecproai.com</strong>
          </p>
        </div>

        <button onClick={onClose} className="btn btn-md btn-ghost" style={{ width:"100%" }}>Fechar</button>
      </div>
    </div>
  );
}

export default function Billing() {
  const { user }  = useAuth();
  const [, setLocation] = useLocation();
  const [billing, setBilling] = useState<"monthly" | "yearly">("monthly");
  const [pixPlan, setPixPlan] = useState<typeof PLANS[0] | null>(null);
  const currentPlan = (user as any)?.plan || "free";

  // Lê configuração de Pix do admin
  const { data: settings } = trpc.admin.getSettings.useQuery();
  const pixEnabled = (settings as any)?.pix_enabled !== "false";

  const createCheckout = trpc.subscriptions.createCheckout.useMutation({
    onSuccess: (data) => { if (data.url) window.location.href = data.url; },
    onError:   (e)    => toast.error(`Erro no checkout: ${e.message}`),
  });

  return (
    <Layout>
      <div style={{ marginBottom:28 }}>
        <button className="btn btn-sm btn-ghost" onClick={() => setLocation("/my-subscription")} style={{ paddingLeft:0, marginBottom:10 }}>← Assinatura</button>
        <h1 style={{ fontFamily:"var(--font-display)", fontSize:24, fontWeight:800, color:"var(--black)", marginBottom:4 }}>Planos e Preços</h1>
        <p style={{ fontSize:13, color:"var(--muted)" }}>Pague com Cartão ou Pix — ativação automática ou em até 2h</p>
      </div>

      {/* Toggle mensal/anual */}
      <div style={{ display:"flex", justifyContent:"center", marginBottom:32 }}>
        <div style={{ display:"flex", background:"var(--off)", borderRadius:10, padding:4, gap:4 }}>
          {(["monthly","yearly"] as const).map(b => (
            <button key={b} onClick={() => setBilling(b)} style={{
              padding:"8px 20px", borderRadius:8, border:"none", cursor:"pointer", fontSize:13, fontWeight:600,
              background: billing === b ? "white" : "transparent",
              color:      billing === b ? "var(--black)" : "var(--muted)",
              boxShadow:  billing === b ? "var(--shadow-xs)" : "none",
            }}>
              {b === "monthly" ? "Mensal" : "Anual"}{b === "yearly" && <span style={{ color:"var(--green-d)", fontSize:11, marginLeft:4 }}>-20%</span>}
            </button>
          ))}
        </div>
      </div>

      {/* Cards */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit, minmax(220px, 1fr))", gap:20, marginBottom:40 }}>
        {PLANS.map(p => {
          const price     = billing === "yearly" ? Math.round(p.price * 0.8) : p.price;
          const isCurrent = currentPlan === p.slug;
          const pixValor  = PIX_DATA[`${p.slug}_${billing}`]?.valor;

          return (
            <div key={p.slug} style={{
              background:"white", border:`2px solid ${p.highlight ? "var(--green)" : "var(--border)"}`,
              borderRadius:16, padding:28, position:"relative",
              boxShadow: p.highlight ? "0 0 0 4px rgba(34,197,94,.08)" : "none",
            }}>
              {p.highlight && (
                <div style={{ position:"absolute", top:-12, left:"50%", transform:"translateX(-50%)", background:"var(--green)", color:"white", fontSize:11, fontWeight:700, padding:"3px 16px", borderRadius:20 }}>MAIS POPULAR</div>
              )}
              {isCurrent && (
                <div style={{ position:"absolute", top:16, right:16, background:"var(--green-xl)", color:"var(--green-dk)", fontSize:10, fontWeight:700, padding:"2px 8px", borderRadius:6 }}>PLANO ATUAL</div>
              )}

              <p style={{ fontSize:11, fontWeight:700, color:"var(--muted)", textTransform:"uppercase", letterSpacing:1, marginBottom:6 }}>{PLAN_EMOJI[p.slug]} {p.name}</p>
              <div style={{ display:"flex", alignItems:"flex-end", gap:4, marginBottom:4 }}>
                <span style={{ fontSize:36, fontWeight:800, color:"var(--black)", fontFamily:"var(--font-display)" }}>R$ {price}</span>
                <span style={{ fontSize:13, color:"var(--muted)", marginBottom:8 }}>/mês</span>
              </div>
              {billing === "yearly" && pixValor && pixEnabled && (
                <p style={{ fontSize:12, color:"var(--green-d)", fontWeight:600, marginBottom:4 }}>
                  R$ {pixValor.toFixed(2).replace(".",",")} à vista no Pix anual
                </p>
              )}
              <p style={{ fontSize:13, color:"var(--muted)", marginBottom:20 }}>{p.desc}</p>

              <div style={{ marginBottom:24 }}>
                {p.features.map((f, i) => (
                  <div key={i} style={{ display:"flex", gap:8, alignItems:"center", marginBottom:8 }}>
                    <span style={{ color:"var(--green)", fontSize:14 }}>✓</span>
                    <span style={{ fontSize:13, color:"var(--body)" }}>{f}</span>
                  </div>
                ))}
              </div>

              <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
                {/* Cartão */}
                <button
                  className={`btn btn-md btn-full ${p.highlight ? "btn-green" : "btn-outline"}`}
                  disabled={isCurrent}
                  onClick={() => createCheckout.mutate({ planSlug: p.slug as any, billing })}>
                  {isCurrent ? "✓ Plano atual" : "💳 Pagar com Cartão"}
                </button>

                {/* Pix — só exibe se pixEnabled e não for plano atual */}
                {!isCurrent && pixEnabled && (
                  <button
                    onClick={() => setPixPlan(p)}
                    style={{
                      width:"100%", padding:"10px 16px", borderRadius:10,
                      border:"2px solid #32bcad", background:"white", color:"#1a9e90",
                      fontWeight:700, fontSize:13, cursor:"pointer",
                      display:"flex", alignItems:"center", justifyContent:"center", gap:8,
                    }}>
                    <span style={{ fontSize:16 }}>⚡</span> Pagar com Pix
                  </button>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* Garantia */}
      <div style={{ background:"var(--green-l)", border:"1px solid var(--green-xl)", borderRadius:14, padding:20, textAlign:"center" }}>
        <p style={{ fontSize:22, marginBottom:6 }}>🔒</p>
        <p style={{ fontSize:14, fontWeight:700, color:"var(--green-dk)", marginBottom:4 }}>Garantia de 7 dias</p>
        <p style={{ fontSize:13, color:"var(--green-d)" }}>Se não ficar satisfeito, devolvemos 100% do valor sem perguntas.</p>
      </div>

      {/* Modal Pix */}
      {pixPlan && (
        <PixModal plan={pixPlan} billing={billing} onClose={() => setPixPlan(null)} />
      )}
    </Layout>
  );
}
